export function AnimatedLogo() {
  const [phase, setPhase] = useState<
    'idle' | 'pane1' | 'pane2' | 'pane3' | 'pane4' | 'triangle' | 'roof' | 'text' | 'slogan1' | 'slogan2' | 'done'
  >('idle');

  useEffect(() => {
    const t1  = setTimeout(() => setPhase('pane1'),    600);
    const t2  = setTimeout(() => setPhase('pane2'),   1100);
    const t3  = setTimeout(() => setPhase('pane3'),   1600);
    const t4  = setTimeout(() => setPhase('pane4'),   2100);
    const t5  = setTimeout(() => setPhase('triangle'), 2800);
    const t6  = setTimeout(() => setPhase('roof'),     3600);
    const t7  = setTimeout(() => setPhase('text'),     5600);
    const t8  = setTimeout(() => setPhase('slogan1'),  6400);
    const t9  = setTimeout(() => setPhase('slogan2'),  7200);
    const t10 = setTimeout(() => setPhase('done'),     8000);
    return () => { [t1,t2,t3,t4,t5,t6,t7,t8,t9,t10].forEach(clearTimeout); };
  }, []);

  const at = (p: string) => {
    const order = ['idle','pane1','pane2','pane3','pane4','triangle','roof','text','slogan1','slogan2','done'];
    return order.indexOf(phase) >= order.indexOf(p);
  };

  // unused utility kept for reference

  return (
    <div className="flex flex-col items-center justify-center select-none w-full">
      {/* === LOGO SVG with layered clip-path reveals === */}
      <div className="relative mb-4" style={{ width: 320, maxWidth: '100%', aspectRatio: '352/188' }}>
        {/* Layer: full logo (base) — appears only after roof */}
        <div style={{
          position: 'absolute', inset: 0,
          opacity: at('roof') ? 1 : 0,
          transition: 'opacity 0.4s ease',
          transitionDelay: '0.2s',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: roof + chimney + wall (rises from bottom to top) */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('roof') ? undefined : 'inset(100% 0 0 0)',
          transition: 'clip-path 1.0s cubic-bezier(0.4, 0, 0.2, 1)',
          transitionDelay: '0.1s',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: inner triangle (rises from bottom to top) */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('triangle') ? undefined : 'inset(100% 0 0 0)',
          transition: 'clip-path 0.7s cubic-bezier(0.4, 0, 0.2, 1)',
          transitionDelay: '0.1s',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: window pane top-left */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('pane1') ? 'polygon(42% 64%, 50% 64%, 50% 72%, 42% 72%)' : 'inset(0 100% 100% 0)',
          transition: 'clip-path 0.01s linear',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: window pane top-right */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('pane2') ? 'polygon(50% 64%, 58% 64%, 58% 72%, 50% 72%)' : 'inset(0 0 100% 100%)',
          transition: 'clip-path 0.01s linear',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: window pane bottom-left */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('pane3') ? 'polygon(42% 72%, 50% 72%, 50% 80%, 42% 80%)' : 'inset(100% 100% 0 0)',
          transition: 'clip-path 0.01s linear',
        }}>
          {SVG_LOGO}
        </div>

        {/* Layer: window pane bottom-right */}
        <div style={{
          position: 'absolute', inset: 0,
          clipPath: at('pane4') ? 'polygon(50% 72%, 58% 72%, 58% 80%, 50% 80%)' : 'inset(100% 0 0 100%)',
          transition: 'clip-path 0.01s linear',
        }}>
          {SVG_LOGO}
        </div>

        {/* Spacer to maintain height */}
        <div style={{ opacity: 0, pointerEvents: 'none' }}>{SVG_LOGO}</div>
      </div>

      {/* === TEXT: LMDreams === */}
      <div className="overflow-hidden" style={{ height: '34px' }}>
        <div
          className="text-3xl md:text-4xl font-heading font-400 tracking-tight whitespace-nowrap"
          style={{
            color: '#c43333',
            transform: at('text') ? 'translateY(0)' : 'translateY(100%)',
            opacity: at('text') ? 1 : 0,
            transition: 'transform 0.6s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s ease',
          }}
        >
          LMDreams
        </div>
      </div>

      {/* === SLOGAN === */}
      <div className="relative overflow-hidden mt-2" style={{ height: '24px', width: '320px', maxWidth: '100%' }}>
        <span
          className="absolute text-sm md:text-base tracking-wider whitespace-nowrap font-500"
          style={{
            color: '#c8d92e',
            left: '50%',
            transform: at('slogan1') ? 'translateX(calc(-100% - 4px))' : 'translateX(calc(-120%))',
            opacity: at('slogan1') ? 1 : 0,
            transition: 'transform 0.7s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.5s ease',
          }}
        >
          O seu sonho
        </span>
        <span
          className="absolute text-sm md:text-base tracking-wider whitespace-nowrap font-500"
          style={{
            color: '#c8d92e',
            left: '50%',
            transform: at('slogan2') ? 'translateX(4px)' : 'translateX(30%)',
            opacity: at('slogan2') ? 1 : 0,
            transition: 'transform 0.7s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.5s ease',
          }}
        >
          , a nossa obra.
        </span>
      </div>
    </div>
  );
}
